async function main() {
  console.log('🌱 Seeding Gastronomía (' + restaurants.length + ' items)...')
  await db.gastronomyRestaurant.deleteMany()
  for (const r of restaurants) {
    await db.gastronomyRestaurant.create({ data: r })
  }
  console.log('✅ ' + restaurants.length + ' items de gastronomía creados')
}

main().then(() => process.exit(0)).catch(e => { console.error(e); process.exit(1) })
